module Compare(
    input  [31:0] A,
    input  [31:0] B,
    output EQ,
    output GZ,
    output LZ,
    output GEZ,
    output LEZ
    );
    wire   ZeroA = (A == 32'b0);
    assign EQ  = ( A == B);
    assign GZ  = (~A[31] & ~ZeroA);
    assign LZ  =   A[31];
    assign GEZ =  ~A[31];
    assign LEZ = ( A[31] |  ZeroA);
  always @(*) begin
    if (1'b0) begin
      if (A[31]) begin
        EQ <= 1'b0;
        GZ <= 1'b0;
        LZ <= 1'b1;
        GEZ <= 1'b0;
        LEZ <= 1'b1;
      end else begin
        EQ <= 1'b1;
        GZ <= 1'b1;
        LZ <= 1'b0;
        GEZ <= 1'b1;
        LEZ <= 1'b0;
      end
    end
  end

endmodule

